-- Validate plugin code against forbidden patterns
local function validate_code(code, plugin_name)
    if not code or type(code) ~= "string" then
        return false, "Plugin code must be a non-empty string"
    end

    if #code > MAX_CODE_SIZE then
        return false, string.format("Plugin code exceeds maximum size of %d bytes (got %d)",
            MAX_CODE_SIZE, #code)
    end

    if #code == 0 then
        return false, "Plugin code is empty"
    end

    -- Check for forbidden patterns
    for _, pattern in ipairs(FORBIDDEN_PATTERNS) do
        local match_start, match_end = code:find(pattern)
        if match_start then
            local context = code:sub(math.max(1, match_start - 20), math.min(#code, match_end + 20))
            ngx.log(ngx.WARN, string.format(
                "[plugin-loader] BLOCKED plugin '%s': forbidden pattern '%s' found near: ...%s...",
                tostring(plugin_name), pattern, context
            ))
            return false, "Plugin code contains forbidden operation"
        end
    end

    -- Verify the code compiles without executing
    local fn, err = load(code, "plugin_validation", "t")
    if not fn then
        return false, "Plugin code has syntax errors: " .. tostring(err)
    end

    return true
end

-- Compute a simple hash for cache invalidation
local function compute_code_hash(code)
    return ngx.md5(code)
end

-- Load and compile plugin code with sandboxing
local function compile_plugin(code, plugin_name)
    local ok, err = validate_code(code, plugin_name)
    if not ok then
        return nil, err
    end

    local sandbox = build_sandbox_env()

    -- Use load() with the sandbox environment
    -- The 't' mode restricts to text chunks only (no bytecode)
    local chunk_name = "@plugin:" .. tostring(plugin_name)
    local fn, load_err = load(code, chunk_name, "t", sandbox)
    if not fn then
        return nil, "Failed to compile plugin: " .. tostring(load_err)
    end

    return fn
end

-- Execute a compiled plugin function with timeout protection
local function execute_plugin(fn, plugin_name, ctx)
    -- Execute in protected call
    local start_time = ngx.now()
    local ok, result_or_err = pcall(fn)
    local elapsed = (ngx.now() - start_time) * 1000

    if elapsed > MAX_EXEC_TIME_MS then
        ngx.log(ngx.WARN, string.format(
            "[plugin-loader] Plugin '%s' initialization took %.2fms (limit: %dms)",
            plugin_name, elapsed, MAX_EXEC_TIME_MS
        ))
    end

    if not ok then
        return nil, string.format("Plugin '%s' initialization failed: %s",
            plugin_name, tostring(result_or_err))
    end

    -- Plugin should return a table with handler functions
    if type(result_or_err) ~= "table" then
        return nil, string.format(
            "Plugin '%s' must return a table with handler functions, got %s",
            plugin_name, type(result_or_err))
    end

    -- Validate the plugin interface
    local plugin_obj = result_or_err
    local has_handler = false
    local valid_handlers = {
        access = true,
        header_filter = true,
        body_filter = true,
        log = true,
        rewrite = true,
    }

    for key, val in pairs(plugin_obj) do
        if valid_handlers[key] then
            if type(val) ~= "function" then
                return nil, string.format(
                    "Plugin '%s' handler '%s' must be a function, got %s",
                    plugin_name, key, type(val))
            end
            has_handler = true
        end
    end

    if not has_handler then
        return nil, string.format(
            "Plugin '%s' must define at least one handler (access, header_filter, body_filter, log, rewrite)",
            plugin_name)
    end

    return plugin_obj
end

-- Connect to Redis
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(2000)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. tostring(err)
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local auth_ok, auth_err = red:auth(REDIS_PASSWORD)
        if not auth_ok then
            red:close()
            return nil, "Redis authentication failed: " .. tostring(auth_err)
        end
    end

    return red
end

-- Return Redis connection to the pool
local function release_redis(red)
    if red then
        local ok, err = red:set_keepalive(10000, 100)
        if not ok then
            ngx.log(ngx.WARN, "[plugin-loader] Failed to set Redis keepalive: ", err)
            red:close()
        end
    end
end

-- Load plugin code from Redis
local function load_plugin_from_redis(plugin_name)
    local red, err = get_redis_connection()
    if not red then
        return nil, nil, err
    end

    -- Get plugin metadata and code atomically
    red:init_pipeline()
    red:hget(REDIS_PLUGIN_PREFIX .. plugin_name, "code")
    red:hget(REDIS_PLUGIN_PREFIX .. plugin_name, "enabled")
    red:hget(REDIS_PLUGIN_PREFIX .. plugin_name, "version")
    red:hget(REDIS_PLUGIN_PREFIX .. plugin_name, "hash")
    local results, pipeline_err = red:commit_pipeline()
    release_redis(red)

    if not results then
        return nil, nil, "Redis pipeline error: " .. tostring(pipeline_err)
    end

    local code = results[1]
    local enabled = results[2]
    local version = results[3]
    local stored_hash = results[4]

    if code == ngx.null or not code then
        return nil, nil, "Plugin '" .. plugin_name .. "' not found in Redis"
    end

    if enabled == "false" or enabled == "0" then
        return nil, nil, "Plugin '" .. plugin_name .. "' is disabled"
    end

    -- Verify integrity if hash is stored
    if stored_hash and stored_hash ~= ngx.null then
        local computed_hash = compute_code_hash(code)
        if computed_hash ~= stored_hash then
            ngx.log(ngx.ERR, string.format(
                "[plugin-loader] INTEGRITY CHECK FAILED for plugin '%s': expected hash %s, got %s",
                plugin_name, stored_hash, computed_hash
            ))
            return nil, nil, "Plugin integrity check failed"
        end
    end

    local meta = {
        version = (version ~= ngx.null) and version or "unknown",
        hash = compute_code_hash(code),
    }

    return code, meta
end

-- Get or compile a plugin, using cache when possible
local function get_plugin(plugin_name)
    -- Check worker-level LRU cache first (per-worker, no serialization needed)
    -- We use ngx.ctx for request-scoped caching and shared dict for cross-request
    local cache_key = "compiled:" .. plugin_name

    -- Check shared dict for version/hash to detect changes
    local cached_hash = plugin_cache and plugin_cache:get(cache_key .. ":hash")

    -- Load from Redis
    local code, meta, err = load_plugin_from_redis(plugin_name)
    if not code then
        return nil, err
    end

    -- If cached version matches, try to use cached compilation result
    -- Note: We still need to recompile since we can't serialize Lua functions
    -- The cache here is used for hash comparison to log when plugins change
    if cached_hash and cached_hash == meta.hash then
        ngx.log(ngx.DEBUG, "[plugin-loader] Plugin '", plugin_name, "' unchanged (hash match)")
    elseif cached_hash then
        ngx.log(ngx.INFO, string.format(
            "[plugin-loader] Plugin '%s' changed (old hash: %s, new hash: %s)",
            plugin_name, cached_hash, meta.hash
        ))
    end

    -- Compile the plugin
    local fn, compile_err = compile_plugin(code, plugin_name)
    if not fn then
        return nil, compile_err
    end

    -- Execute to get the plugin object
    local plugin_obj, exec_err = execute_plugin(fn, plugin_name, nil)
    if not plugin_obj then
        return nil, exec_err
    end

    -- Update cache
    if plugin_cache then
        plugin_cache:set(cache_key .. ":hash", meta.hash, 300) -- 5 min TTL
    end

    plugin_obj._meta = meta
    return plugin_obj
end

-- Authenticate admin requests
local function authenticate_admin()
    local api_key = ngx.req.get_headers()["X-Admin-API-Key"]
    if not api_key or api_key ~= ADMIN_API_KEY then
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.say(cjson.encode({
            error = "Unauthorized",
            message = "Valid X-Admin-API-Key header required"
        }))
        ngx.exit(ngx.HTTP_UNAUTHORIZED)
        return false
    end
    return true
end

-- Validate plugin name to prevent injection in Redis keys
local function validate_plugin_name(name)
    if not name or type(name) ~= "string" then
        return false, "Plugin name must be a non-empty string"
    end
    if #name < 1 or #name > 128 then
        return false, "Plugin name must be between 1 and 128 characters"
    end
    -- Only allow alphanumeric, hyphens, underscores
    if not name:match("^[a-zA-Z][a-zA-Z0-9_%-]*$") then
        return false, "Plugin name must start with a letter and contain only alphanumeric characters, hyphens, and underscores"
    end
    return true
end

-- Admin API: Register a plugin
local function handle_register_plugin()
    if not authenticate_admin() then return end

    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({ error = "Request body required" }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local data, decode_err = cjson.decode(body)
    if not data then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({ error = "Invalid JSON: " .. tostring(decode_err) }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local plugin_name = data.name
    local plugin_code = data.code
    local enabled = data.enabled ~= false -- default true

    -- Validate plugin name
    local name_ok, name_err = validate_plugin_name(plugin_name)
    if not name_ok then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({ error = name_err }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    -- Validate the code before storing
    local code_ok, code_err = validate_code(plugin_code, plugin_name)
    if not code_ok then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({
            error = "Plugin validation failed",
            details = code_err
        }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    -- Test compile and execute to verify it works
    local fn, compile_err = compile_plugin(plugin_code, plugin_name)
    if not fn then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({
            error = "Plugin compilation failed",
            details = compile_err
        }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local plugin_obj, exec_err = execute_plugin(fn, plugin_name, nil)
    if not plugin_obj then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({
            error = "Plugin execution test failed",
            details = exec_err
        }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    -- Store in Redis
    local red, redis_err = get_redis_connection()
    if not red then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say(cjson.encode({ error = "Redis connection failed: " .. tostring(redis_err) }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    local code_hash = compute_code_hash(plugin_code)
    local version = tostring(ngx.now())

    red:init_pipeline()
    red:hset(REDIS_PLUGIN_PREFIX .. plugin_name, "code", plugin_code)
    red:hset(REDIS_PLUGIN_PREFIX .. plugin_name, "enabled", tostring(enabled))
    red:hset(REDIS_PLUGIN_PREFIX .. plugin_name, "version", version)
    red:hset(REDIS_PLUGIN_PREFIX .. plugin_name, "hash", code_hash)
    red:hset(REDIS_PLUGIN_PREFIX .. plugin_name, "registered_at", ngx.localtime())
    red:hset(REDIS_PLUGIN_PREFIX .. plugin_name, "registered_by", ngx.var.remote_addr)

    -- Add to the plugin registry set
    red:sadd("gateway:plugins:registry", plugin_name)

    local results, pipeline_err = red:commit_pipeline()
    release_redis(red)

    if not results then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say(cjson.encode({ error = "Failed to store plugin: " .. tostring(pipeline_err) }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete("compiled:" .. plugin_name .. ":hash")
    end

    -- List available handlers
    local handlers = {}
    for key, val in pairs(plugin_obj) do
        if type(val) == "function" and key ~= "_meta" then
            handlers[#handlers + 1] = key
        end
    end

    ngx.log(ngx.INFO, string.format(
        "[plugin-loader] Plugin '%s' registered successfully (hash: %s, handlers: %s)",
        plugin_name, code_hash, table.concat(handlers, ", ")
    ))

    ngx.status = ngx.HTTP_OK
    ngx.say(cjson.encode({
        status = "registered",
        plugin = plugin_name,
        version = version,
        hash = code_hash,
        enabled = enabled,
        handlers = handlers,
    }))
end

-- Admin API: List all registered plugins
local function handle_list_plugins()
    if not authenticate_admin() then return end

    local red, err = get_redis_connection()
    if not red then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say(cjson.encode({ error = "Redis connection failed: " .. tostring(err) }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    local members, smembers_err = red:smembers("gateway:plugins:registry")
    if not members then
        release_redis(red)
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say(cjson.encode({ error = "Failed to list plugins: " .. tostring(smembers_err) }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    local plugins = {}
    for _, name in ipairs(members) do
        local info = red:hgetall(REDIS_PLUGIN_PREFIX .. name)
        if info and info ~= ngx.null then
            local plugin_info = { name = name }
            for i = 1, #info, 2 do
                if info[i] ~= "code" then -- Don't include code in listing
                    plugin_info[info[i]] = info[i + 1]
                end
            end
            plugin_info.code_size = red:hstrlen(REDIS_PLUGIN_PREFIX .. name, "code")
            plugins[#plugins + 1] = plugin_info
        end
    end

    release_redis(red)

    ngx.status = ngx.HTTP_OK
    ngx.say(cjson.encode({
        count = #plugins,
        plugins = plugins,
    }))
end

-- Admin API: Delete a plugin
local function handle_delete_plugin(plugin_name)
    if not authenticate_admin() then return end

    local name_ok, name_err = validate_plugin_name(plugin_name)
    if not name_ok then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({ error = name_err }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local red, err = get_redis_connection()
    if not red then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say(cjson.encode({ error = "Redis connection failed: " .. tostring(err) }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    red:init_pipeline()
    red:del(REDIS_PLUGIN_PREFIX .. plugin_name)
    red:srem("gateway:plugins:registry", plugin_name)
    local results, pipeline_err = red:commit_pipeline()
    release_redis(red)

    if not results then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say(cjson.encode({ error = "Failed to delete plugin: " .. tostring(pipeline_err) }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete("compiled:" .. plugin_name .. ":hash")
    end

    ngx.log(ngx.INFO, "[plugin-loader] Plugin '", plugin_name, "' deleted")

    ngx.status = ngx.HTTP_OK
    ngx.say(cjson.encode({
        status = "deleted",
        plugin = plugin_name,
    }))
end

-- Admin API: Enable/disable a plugin
local function handle_toggle_plugin(plugin_name, enable)
    if not authenticate_admin() then return end

    local name_ok, name_err = validate_plugin_name(plugin_name)
    if not name_ok then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({ error = name_err }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local red, err = get_redis_connection()
    if not red then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say(cjson.encode({ error = "Redis connection failed: " .. tostring(err) }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    local exists = red:exists(REDIS_PLUGIN_PREFIX .. plugin_name)
    if exists == 0 then
        release_redis(red)
        ngx.status = ngx.HTTP_NOT_FOUND
        ngx.say(cjson.encode({ error = "Plugin not found: " .. plugin_name }))
        return ngx.exit(ngx.HTTP_NOT_FOUND)
    end

    red:hset(REDIS_PLUGIN_PREFIX .. plugin_name, "enabled", tostring(enable))
    release_redis(red)

    ngx.log(ngx.INFO, string.format(
        "[plugin-loader] Plugin '%s' %s", plugin_name, enable and "enabled" or "disabled"
    ))

    ngx.status = ngx.HTTP_OK
    ngx.say(cjson.encode({
        status = enable and "enabled" or "disabled",
        plugin = plugin_name,
    }))
end

-- Execute the plugin pipeline for the current request
local function run_plugin_pipeline(phase)
    -- Get the list of active plugins for this route/request
    local plugin_header = ngx.req.get_headers()["X-Gateway-Plugins"]
    if not plugin_header then
        return -- No plugins requested
    end

    -- Parse comma-separated plugin names
    local plugin_names = {}
    for name in plugin_header:gmatch("([^,]+)") do
        name = name:match("^%s*(.-)%s*$") -- trim whitespace
        if name and #name > 0 then
            local name_ok = validate_plugin_name(name)
            if name_ok then
                plugin_names[#plugin_names + 1] = name
            else
                ngx.log(ngx.WARN, "[plugin-loader] Skipping invalid plugin name: ", name)
            end
        end
    end

    -- Execute each plugin's handler for the current phase
    for _, plugin_name in ipairs(plugin_names) do
        local plugin_obj, err = get_plugin(plugin_name)
        if not plugin_obj then
            ngx.log(ngx.ERR, string.format(
                "[plugin-loader] Failed to load plugin '%s': %s", plugin_name, err
            ))
            -- Continue with other plugins rather than failing the request
            goto continue
        end

        local handler = plugin_obj[phase]
        if handler then
            local start_time = ngx.now()
            local ok, handler_err = pcall(handler, {
                -- Pass a controlled context to the handler
                plugin_name = plugin_name,
                phase = phase,
            })
            local elapsed = (ngx.now() - start_time) * 1000

            if not ok then
                ngx.log(ngx.ERR, string.format(
                    "[plugin-loader] Plugin '%s' %s handler error (%.2fms): %s",
                    plugin_name, phase, elapsed, tostring(handler_err)
                ))
            else
                ngx.log(ngx.DEBUG, string.format(
                    "[plugin-loader] Plugin '%s' %s handler completed in %.2fms",
                    plugin_name, phase, elapsed
                ))
            end
        end

        ::continue::
    end
end

-- Main request router
local function main()
    local method = ngx.req.get_method()
    local uri = ngx.var.uri

    -- Admin API routes
    if uri == "/gateway/plugins" then
        if method == "POST" then
            return handle_register_plugin()
        elseif method == "GET" then
            return handle_list_plugins()
        end
    end

    -- Match /gateway/plugins/{name}
    local plugin_name_match = uri:match("^/gateway/plugins/([^/]+)$")
    if plugin_name_match then
        if method == "DELETE" then
            return handle_delete_plugin(plugin_name_match)
        end
    end

    -- Match /gateway/plugins/{name}/enable or /disable
    local toggle_name, toggle_action = uri:match("^/gateway/plugins/([^/]+)/(enable|disable)$")
    if toggle_name and toggle_action then
        if method == "POST" or method == "PUT" then
            return handle_toggle_plugin(toggle_name, toggle_action == "enable")
        end
    end

    -- For non-admin routes, run the plugin pipeline
    run_plugin_pipeline("access")
end

-- Execute
main()